describe("renderFlow", () => {
    it("returns a single monolith file equal to renderMarkdown", () => {
        const flow = makeFlow();
        const files = renderFlow(flow, TARGETS.claude);
        expect(files).toHaveLength(1);
        expect(files[0].kind).toBe("monolith");
        expect(files[0].slug).toBe("");
        expect(files[0].content).toBe(renderMarkdown(flow, TARGETS.claude));
    });
    it("inlining every phase emits only an orchestrator (no sub-skills)", () => {
        const flow = makeFlow({
            compile: { mode: "split", inlinePhases: ["main"] },
        });
        const files = renderFlow(flow, TARGETS.claude);
        expect(files).toHaveLength(1);
        expect(files[0].kind).toBe("orchestrator");
        expect(files[0].slug).toBe("");
        // The inlined phase's step renders inside the orchestrator.
        expect(files[0].content).toContain("Body A");
    });
    it("splits a non-inline phase into the orchestrator plus a sub-skill", () => {
        const flow = makeFlow({
            compile: { mode: "split", inlinePhases: [] },
        });
        const files = renderFlow(flow, TARGETS.claude);
        expect(files).toHaveLength(2);
        const orchestrator = files.find((f) => f.kind === "orchestrator");
        const sub = files.find((f) => f.kind === "phase");
        expect(orchestrator?.slug).toBe("");
        expect(sub?.slug).toBe("main");
        // The orchestrator dispatches to the sub-skill by name and omits the body.
        expect(orchestrator?.content).toContain("Invoke the `test-main` skill");
        expect(orchestrator?.content).not.toContain("Body A");
        // The Claude sub-skill is an Agent Skill (name: frontmatter), hidden from
        // the `/` menu but model-invocable, carries the phase body and its own H1.
        expect(sub?.content).toContain("name: test-main");
        expect(sub?.content).toContain("user-invocable: false");
        expect(sub?.content).toContain("Body A");
        expect(sub?.content).toContain("# Test: Main");
    });
    it("names split sub-skills per target (Claude/Cursor/Codex frontmatter)", () => {
        const flow = makeFlow({ compile: { mode: "split", inlinePhases: [] } });
        // Dispatch wording is target-neutral (invoke by sub-skill name).
        for (const target of [TARGETS.claude, TARGETS.cursor, TARGETS.codex]) {
            expect(renderFlow(flow, target).find((f) => f.kind === "orchestrator")
                ?.content).toContain("Invoke the `test-main` skill");
        }
        // Cursor prefixes skill names with `bitfab-`; Claude/Codex do not.
        expect(renderFlow(flow, TARGETS.cursor).find((f) => f.kind === "phase")?.content).toContain("name: bitfab-test-main");
        expect(renderFlow(flow, TARGETS.codex).find((f) => f.kind === "phase")?.content).toContain("name: test-main");
    });
    it("orchestrator allowed-tools include the Skill tool plus inline-phase tools", () => {
        const flow = makeFlow({
            tools: { bash: { kind: "builtin", name: "Bash" } },
            entries: { all: "setup/run" },
            compile: { mode: "split", inlinePhases: ["setup"] },
            phases: [
                {
                    id: "setup",
                    title: "Setup",
                    stepStyle: "list",
                    steps: [
                        {
                            id: "run",
                            kind: "action",
                            toolCalls: ["bash"],
                            title: "Run",
                            body: "Run it",
                            next: "work/do",
                        },
                    ],
                },
                {
                    id: "work",
                    title: "Work",
                    stepStyle: "list",
                    steps: [
                        {
                            id: "do",
                            kind: "action",
                            title: "Do",
                            body: "Do it",
                            next: null,
                        },
                    ],
                },
            ],
        });
        const orchestrator = renderFlow(flow, TARGETS.claude).find((f) => f.kind === "orchestrator");
        expect(orchestrator?.content).toContain('allowed-tools: ["Bash", "Skill"]');
    });
    it("per-target mode splits one target; others stay monolith", () => {
        const flow = makeFlow({
            compile: { mode: { default: "monolith", claude: "split" } },
        });
        const claude = renderFlow(flow, TARGETS.claude);
        expect(claude).toHaveLength(2);
        expect(claude.map((f) => f.kind)).toEqual(["orchestrator", "phase"]);
        for (const target of [TARGETS.cursor, TARGETS.codex]) {
            const files = renderFlow(flow, target);
            expect(files).toHaveLength(1);
            expect(files[0].kind).toBe("monolith");
            expect(files[0].content).toBe(renderMarkdown(flow, target));
        }
    });
});
describe("renderFlow: compile.entry skill | command", () => {
    it("defaults the entry to a Claude command (no name:, /-typed)", () => {
        const monolith = renderFlow(makeFlow(), TARGETS.claude)[0];
        expect(monolith.content).toContain("description: Desc");
        expect(monolith.content).not.toContain("name: test");
        expect(monolith.content).not.toContain("user-invocable:");
    });
    it("renders a monolith entry as a model-invocable skill when entry: skill", () => {
        const flow = makeFlow({ compile: { entry: "skill" } });
        const monolith = renderFlow(flow, TARGETS.claude)[0];
        expect(monolith.kind).toBe("monolith");
        // Agent Skill frontmatter: name + user-invocable so it stays in the `/` menu
        // while becoming callable via the Skill tool.
        expect(monolith.content).toContain("name: test");
        expect(monolith.content).toContain("user-invocable: true");
    });
    it("renders a split orchestrator entry as a skill when entry: skill", () => {
        const flow = makeFlow({
            compile: { mode: "split", inlinePhases: [], entry: "skill" },
        });
        const files = renderFlow(flow, TARGETS.claude);
        const orchestrator = files.find((f) => f.kind === "orchestrator");
        const sub = files.find((f) => f.kind === "phase");
        // The orchestrator is now a user-invocable Agent Skill...
        expect(orchestrator?.content).toContain("name: test");
        expect(orchestrator?.content).toContain("user-invocable: true");
        // ...while its phase sub-skills stay hidden (user-invocable: false).
        expect(sub?.content).toContain("user-invocable: false");
    });
    it("entry skill keeps argument-hint for the / menu; hidden sub-skills omit it", () => {
        const flow = makeFlow({
            compile: { mode: "split", inlinePhases: [], entry: "skill" },
            frontmatter: {
                description: "Desc",
                argumentHint: "[local | remote | help] [TICKET-ID]",
            },
        });
        const files = renderFlow(flow, TARGETS.claude);
        const orchestrator = files.find((f) => f.kind === "orchestrator");
        const sub = files.find((f) => f.kind === "phase");
        // The user-invocable entry skill shows the usage hint...
        expect(orchestrator?.content).toContain('argument-hint: "[local | remote | help] [TICKET-ID]"');
        // ...the hidden, model-only sub-skill does not.
        expect(sub?.content).not.toContain("argument-hint:");
    });
    it("entry: skill is per-target and leaves Cursor/Codex frontmatter unchanged", () => {
        const command = makeFlow();
        const skill = makeFlow({
            compile: { entry: { default: "command", claude: "skill" } },
        });
        // Claude flips to a skill...
        expect(renderFlow(skill, TARGETS.claude)[0].content).toContain("user-invocable: true");
        // ...Cursor and Codex are already skills via their normal frontmatter, so
        // the flag is a no-op: identical output with or without it.
        for (const target of [TARGETS.cursor, TARGETS.codex]) {
            expect(renderFlow(skill, target)[0].content).toBe(renderFlow(command, target)[0].content);
        }
    });
});
describe("renderFlow: split-chain (tail-call dispatch)", () => {
    /**
     * Update-flow-shaped fixture: shared inline `setup` fanning out by mode,
     * a `plugin` phase that tails into `sdk` in `all` mode but terminates in
     * `plugin` mode, and a terminal `sdk` phase.
     */
    function makeChainFlow(overrides = {}) {
        return makeFlow({
            entries: { all: "setup/run", plugin: "setup/run", sdk: "setup/run" },
            defaultMode: "all",
            tools: { bash: { kind: "builtin", name: "Bash" } },
            compile: { mode: "split-chain", inlinePhases: ["setup"] },
            appendices: [
                { id: "rep", title: "Reporting", body: "How to report" },
                { id: "glob", title: "Global", body: "Global stuff" },
            ],
            phases: [
                {
                    id: "setup",
                    title: "Setup",
                    stepStyle: "list",
                    steps: [
                        {
                            id: "run",
                            kind: "action",
                            toolCalls: ["bash"],
                            title: "Run",
                            body: "Run the script",
                            next: {
                                byMode: {
                                    all: "plugin/report",
                                    plugin: "plugin/report",
                                    sdk: "sdk/parse",
                                },
                            },
                        },
                    ],
                },
                {
                    id: "plugin",
                    title: "Update plugin",
                    stepStyle: "list",
                    steps: [
                        {
                            id: "report",
                            kind: "action",
                            toolCalls: ["bash"],
                            title: "Report",
                            body: "Report the plugin result",
                            next: { byMode: { all: "sdk/parse", plugin: null, sdk: null } },
                        },
                    ],
                },
                {
                    id: "sdk",
                    title: "Update SDK",
                    stepStyle: "list",
                    steps: [
                        {
                            id: "parse",
                            kind: "action",
                            toolCalls: ["bash"],
                            title: "Parse",
                            body: "Parse the status",
                            refs: ["rep"],
                            next: null,
                        },
                    ],
                },
            ],
            ...overrides,
        });
    }
    function fileFor(flow, slug) {
        const file = renderFlow(flow, TARGETS.claude).find((f) => f.slug === slug);
        if (file === undefined) {
            throw new Error(`no rendered file with slug "${slug}"`);
        }
        return file.content;
    }
    it("never emits call-and-return dispatch prose", () => {
        const flow = makeChainFlow();
        for (const file of renderFlow(flow, TARGETS.claude)) {
            expect(file.content).not.toContain("then return here");
        }
    });
    it("emits the same file layout as split (orchestrator + per-phase sub-skills)", () => {
        const flow = makeChainFlow();
        const files = renderFlow(flow, TARGETS.claude);
        expect(files.map((f) => [f.kind, f.slug])).toEqual([
            ["orchestrator", ""],
            ["phase", "plugin"],
            ["phase", "sdk"],
        ]);
    });
    it("renders a grouped byMode fan-out on the inline dispatching step", () => {
        const orchestrator = fileFor(makeChainFlow(), "");
        expect(orchestrator).toContain("**Next:**");
        expect(orchestrator).toContain("- Mode `all` or `plugin`: invoke the `test-plugin` skill with the current mode (`all` or `plugin`).");
        expect(orchestrator).toContain("- Mode `sdk`: invoke the `test-sdk` skill with mode `sdk`.");
    });
    it("contrasts dispatch against done when one mode tails on and another terminates", () => {
        const plugin = fileFor(makeChainFlow(), "plugin");
        expect(plugin).toContain("- Mode `all`: invoke the `test-sdk` skill with mode `all`.");
        expect(plugin).toContain("- Mode `plugin`: stop here.");
    });
    it("emits no Next block on purely terminal steps", () => {
        const sdk = fileFor(makeChainFlow(), "sdk");
        expect(sdk).not.toContain("**Next:**");
    });
    it("prefaces multi-mode sub-skills with the dispatched-mode reminder", () => {
        const flow = makeChainFlow();
        expect(fileFor(flow, "plugin")).toContain("**Mode:** you were dispatched with a mode (`all` or `plugin`);");
        expect(fileFor(flow, "sdk")).toContain("**Mode:** you were dispatched with a mode (`all` or `sdk`);");
    });
    it("describes chain sub-skills as invoked by the flow, not the orchestrator", () => {
        const plugin = fileFor(makeChainFlow(), "plugin");
        expect(plugin).toContain("Invoked by the test flow; not run directly");
        expect(plugin).not.toContain("orchestrator");
    });
    it("adds the Skill tool to dispatching sub-skills only", () => {
        const flow = makeChainFlow();
        expect(fileFor(flow, "plugin")).toContain('allowed-tools: ["Bash", "Skill"]');
        expect(fileFor(flow, "sdk")).toContain('allowed-tools: ["Bash"]');
    });
    it("places appendices with the unit that references them", () => {
        const flow = makeChainFlow();
        const orchestrator = fileFor(flow, "");
        const sdk = fileFor(flow, "sdk");
        // `rep` is ref'd by sdk/parse: lives in the sdk sub-skill only.
        expect(sdk).toContain("## Reporting");
        expect(orchestrator).not.toContain("## Reporting");
        // `glob` is ref'd by nothing: stays flow-global in the orchestrator.
        expect(orchestrator).toContain("## Global");
        expect(sdk).not.toContain("## Global");
    });
    it("renders labeled dispatch lines for cross-unit branch options only", () => {
        const flow = makeChainFlow({
            entries: { all: "setup/run", plugin: "setup/run", sdk: "setup/run" },
            phases: [
                {
                    id: "setup",
                    title: "Setup",
                    stepStyle: "list",
                    steps: [
                        {
                            id: "run",
                            kind: "branch",
                            toolCalls: ["bash"],
                            title: "Choose",
                            body: "Pick one",
                            branches: [
                                {
                                    option: { letter: "A", label: "Do the work" },
                                    next: "work/do",
                                },
                                {
                                    option: { letter: "B", label: "Skip everything" },
                                    next: null,
                                },
                            ],
                        },
                    ],
                },
                {
                    id: "work",
                    title: "Work",
                    stepStyle: "list",
                    steps: [
                        {
                            id: "do",
                            kind: "action",
                            toolCalls: ["bash"],
                            title: "Do",
                            body: "Do it",
                            next: null,
                        },
                    ],
                },
            ],
        });
        const orchestrator = fileFor(flow, "");
        expect(orchestrator).toContain("- Option A (Do the work) (mode `all` or `plugin` or `sdk`): invoke the `test-work` skill with the current mode (`all` or `plugin` or `sdk`).");
        // Option B never dispatches; its "stop" is the body's own prose.
        expect(orchestrator).not.toContain("Option B");
    });
    it("compiles cross-phase loops, which sequential split cannot express", () => {
        const flow = makeFlow({
            entries: { all: "iterate/work" },
            tools: { bash: { kind: "builtin", name: "Bash" } },
            compile: { mode: "split-chain", inlinePhases: [] },
            phases: [
                {
                    id: "iterate",
                    title: "Iterate",
                    stepStyle: "list",
                    steps: [
                        {
                            id: "work",
                            kind: "action",
                            toolCalls: ["bash"],
                            title: "Work",
                            body: "Do one round",
                            next: "check/decide",
                        },
                    ],
                },
                {
                    id: "check",
                    title: "Check",
                    stepStyle: "list",
                    steps: [
                        {
                            id: "decide",
                            kind: "loop",
                            title: "Decide",
                            body: "Evaluate the round",
                            exitWhen: "all items pass",
                            backTo: "iterate/work",
                            onExit: "finish/done",
                        },
                    ],
                },
                {
                    id: "finish",
                    title: "Finish",
                    stepStyle: "list",
                    steps: [
                        {
                            id: "done",
                            kind: "action",
                            title: "Done",
                            body: "Wrap up",
                            next: null,
                        },
                    ],
                },
            ],
        });
        const files = renderFlow(flow, TARGETS.claude);
        const orchestrator = files.find((f) => f.kind === "orchestrator")?.content;
        const check = files.find((f) => f.slug === "check")?.content;
        // Pure dispatcher orchestrator: every mode enters a sub-phase directly.
        expect(orchestrator).toContain("## Dispatch");
        expect(orchestrator).toContain("- Invoke the `test-iterate` skill.");
        // The loop's two edges both dispatch; single-mode flow drops mode prose.
        expect(check).toContain("- All items pass: invoke the `test-finish` skill.");
        expect(check).toContain("- Otherwise: invoke the `test-iterate` skill.");
        // Single-mode flow: no mode preface anywhere.
        expect(check).not.toContain("**Mode:**");
    });
    it("rejects a mode entry pointing mid-way into a non-inline phase", () => {
        expect(() => makeFlow({
            entries: { all: "main/a", extra: "main/b" },
            compile: { mode: "split-chain", inlinePhases: [] },
            phases: [
                {
                    id: "main",
                    title: "Main",
                    stepStyle: "list",
                    steps: [
                        {
                            id: "a",
                            kind: "action",
                            title: "A",
                            body: "A",
                            next: "main/b",
                        },
                        { id: "b", kind: "action", title: "B", body: "B", next: null },
                    ],
                },
            ],
        })).toThrow(/mid-phase/);
    });
    it("rejects sub-skill edges that re-enter an inline phase", () => {
        expect(() => makeFlow({
            entries: { all: "setup/run" },
            compile: { mode: "split-chain", inlinePhases: ["setup"] },
            phases: [
                {
                    id: "setup",
                    title: "Setup",
                    stepStyle: "list",
                    steps: [
                        {
                            id: "run",
                            kind: "action",
                            title: "Run",
                            body: "Run",
                            next: "work/do",
                        },
                    ],
                },
                {
                    id: "work",
                    title: "Work",
                    stepStyle: "list",
                    steps: [
                        {
                            id: "do",
                            kind: "action",
                            title: "Do",
                            body: "Do",
                            next: "setup/run",
                        },
                    ],
                },
            ],
        })).toThrow(/re-enter the orchestrator/);
    });
    it("split (non-chain) output is unchanged by the chain machinery", () => {
        const flow = makeChainFlow({
            compile: { mode: "split", inlinePhases: ["setup"] },
        });
        const orchestrator = fileFor(flow, "");
        expect(orchestrator).toContain("Invoke the `test-plugin` skill, then return here.");
        expect(orchestrator).not.toContain("**Next:**");
        expect(fileFor(flow, "plugin")).not.toContain("**Mode:**");
    });
    describe("file-local {{step:...}} references", () => {
        /**
         * Step numbers are file-local: a `{{step:...}}` ref into a phase that
         * compiles to a different file would render a bare number pointing into
         * another skill — meaningless to the agent reading it. Both split modes
         * reject it; monolith (everything in one file) still allows it.
         */
        function makeCrossRefFlow(compile, body = "After this, run step {{step:sdk/parse}} of the SDK phase.") {
            return makeChainFlow({
                compile,
                phases: [
                    {
                        id: "setup",
                        title: "Setup",
                        stepStyle: "list",
                        steps: [
                            {
                                id: "run",
                                kind: "action",
                                toolCalls: ["bash"],
                                title: "Run",
                                body,
                                next: {
                                    byMode: {
                                        all: "plugin/report",
                                        plugin: "plugin/report",
                                        sdk: "sdk/parse",
                                    },
                                },
                            },
                        ],
                    },
                    {
                        id: "plugin",
                        title: "Update plugin",
                        stepStyle: "list",
                        steps: [
                            {
                                id: "report",
                                kind: "action",
                                toolCalls: ["bash"],
                                title: "Report",
                                body: "Report the plugin result",
                                next: { byMode: { all: "sdk/parse", plugin: null, sdk: null } },
                            },
                        ],
                    },
                    {
                        id: "sdk",
                        title: "Update SDK",
                        stepStyle: "list",
                        steps: [
                            {
                                id: "parse",
                                kind: "action",
                                toolCalls: ["bash"],
                                title: "Parse",
                                body: "Parse the status",
                                next: null,
                            },
                        ],
                    },
                ],
            });
        }
        it("rejects refs that cross a unit boundary, in both split modes", () => {
            for (const mode of ["split", "split-chain"]) {
                const flow = makeCrossRefFlow({ mode, inlinePhases: ["setup"] });
                expect(() => renderFlow(flow, TARGETS.claude)).toThrow(/crosses a split-unit boundary.*`test-sdk` skill by name/);
            }
        });
        it("allows same-unit refs and monolith refs", () => {
            // Same unit: sdk step referencing its own phase's numbering.
            const sameUnit = makeCrossRefFlow({ mode: "split-chain", inlinePhases: ["setup"] }, "Run the script.");
            expect(() => renderFlow(sameUnit, TARGETS.claude)).not.toThrow();
            // Monolith: the cross-phase ref is one file, bare numbers are fine.
            const monolith = makeCrossRefFlow({ mode: "monolith" });
            const out = renderMarkdown(monolith, TARGETS.claude);
            expect(out).toContain("run step 1 of the SDK phase");
        });
    });
});
describe("Renderer: branch destinations and placeholder indentation", () => {
    it("appends step-number destinations to {{branches}} option lines", () => {
        const flow = makeFlow({
            entries: { all: "main/pick" },
            phases: [
                {
                    id: "main",
                    title: "Main",
                    stepStyle: "headers",
                    steps: [
                        {
                            id: "pick",
                            kind: "branch",
                            title: "Pick",
                            body: "{{branches}}",
                            branches: [
                                {
                                    option: { letter: "A", label: "Do it" },
                                    recommended: true,
                                    next: "main/work",
                                },
                                { option: { letter: "B", label: "Skip" }, next: null },
                            ],
                        },
                        {
                            id: "work",
                            kind: "action",
                            title: "Work",
                            body: "Work body",
                            next: null,
                        },
                    ],
                },
            ],
        });
        const out = renderMarkdown(flow, TARGETS.claude);
        expect(out).toContain("> A) **Do it** *(recommended)* → step 2");
        expect(out).toContain("> B) **Skip** → stop");
    });
    it("groups byMode option destinations per target with mode lists", () => {
        const flow = makeFlow({
            entries: { all: "main/pick", quick: "main/pick" },
            phases: [
                {
                    id: "main",
                    title: "Main",
                    stepStyle: "headers",
                    steps: [
                        {
                            id: "pick",
                            kind: "branch",
                            title: "Pick",
                            body: "{{branches}}",
                            branches: [
                                {
                                    option: { letter: "A", label: "Continue" },
                                    next: { byMode: { all: "main/work", quick: null } },
                                },
                                { option: { letter: "B", label: "Bail" }, next: null },
                            ],
                        },
                        {
                            id: "work",
                            kind: "action",
                            title: "Work",
                            body: "Work body",
                            next: null,
                        },
                    ],
                },
            ],
        });
        const out = renderMarkdown(flow, TARGETS.claude);
        expect(out).toContain("> A) **Continue** → step 2 (mode `all`); stop (mode `quick`)");
    });
    it("renders cross-unit option destinations as skill names under split modes", () => {
        const flow = makeFlow({
            entries: { all: "main/pick" },
            compile: { mode: "split-chain", inlinePhases: ["main"] },
            phases: [
                {
                    id: "main",
                    title: "Main",
                    stepStyle: "headers",
                    steps: [
                        {
                            id: "pick",
                            kind: "branch",
                            title: "Pick",
                            body: "{{branches}}",
                            branches: [
                                {
                                    option: { letter: "A", label: "Do the work" },
                                    next: "work/do",
                                },
                                { option: { letter: "B", label: "Skip" }, next: null },
                            ],
                        },
                    ],
                },
                {
                    id: "work",
                    title: "Work",
                    stepStyle: "headers",
                    steps: [
                        {
                            id: "do",
                            kind: "action",
                            title: "Do",
                            body: "Do body",
                            next: null,
                        },
                    ],
                },
            ],
        });
        const orchestrator = renderFlow(flow, TARGETS.claude).find((f) => f.kind === "orchestrator")?.content;
        // No bare step number leaks across the file boundary.
        expect(orchestrator).toContain("> A) **Do the work** → the `test-work` skill");
        expect(orchestrator).toContain("> B) **Skip** → stop");
    });
    it("appends destinations to {{whens}} lines, skipping redundant stops", () => {
        const flow = makeFlow({
            entries: { all: "main/decide" },
            phases: [
                {
                    id: "main",
                    title: "Main",
                    stepStyle: "headers",
                    steps: [
                        {
                            id: "decide",
                            kind: "branch",
                            title: "Decide",
                            body: "{{whens}}",
                            branches: [
                                { when: "it failed", description: "stop the flow", next: null },
                                { when: "it worked", next: "main/done" },
                            ],
                        },
                        {
                            id: "done",
                            kind: "action",
                            title: "Done",
                            body: "End",
                            next: null,
                        },
                    ],
                },
            ],
        });
        const out = renderMarkdown(flow, TARGETS.claude);
        expect(out).toContain("- **it failed**: stop the flow\n");
        expect(out).toContain("- **it worked**: continue → step 2");
    });
    it("indents {{languages:...}} continuation lines to match the placeholder's line", () => {
        const flow = makeFlow({
            entries: { all: "main/scan" },
            languages: [
                {
                    name: "typescript",
                    displayName: "TypeScript",
                    imports: "`import bitfab`",
                },
                { name: "python", displayName: "Python", imports: "`import bitfab`" },
            ],
            phases: [
                {
                    id: "main",
                    title: "Main",
                    stepStyle: "list",
                    steps: [
                        {
                            id: "scan",
                            kind: "action",
                            title: "Scan",
                            body: "- Grep for imports:\n{{languages:imports}}\n- Then proceed.",
                            next: null,
                        },
                    ],
                },
            ],
        });
        const out = renderMarkdown(flow, TARGETS.claude);
        // List body indent is 3 spaces; the imports block's own indent is 2. The
        // first line inherits the placeholder's 3-space prefix in place; the
        // continuation line must be re-indented to match, not dedent to column 2.
        expect(out).toContain("     - TypeScript: `import bitfab`");
        expect(out).toContain("     - Python: `import bitfab`");
        expect(out).not.toContain("\n  - Python");
    });
});
describe("Renderer: branch destination qualification and mode grouping", () => {
    it("qualifies same-file destinations in another phase with the phase title", () => {
        const flow = makeFlow({
            entries: { all: "main/pick" },
            phases: [
                {
                    id: "main",
                    title: "Main",
                    stepStyle: "headers",
                    steps: [
                        {
                            id: "pick",
                            kind: "branch",
                            title: "Pick",
                            body: "{{branches}}",
                            branches: [
                                {
                                    option: { letter: "A", label: "Wrap up" },
                                    next: "finish/done",
                                },
                                { option: { letter: "B", label: "Bail" }, next: null },
                            ],
                        },
                    ],
                },
                {
                    id: "finish",
                    title: "Finish",
                    stepStyle: "headers",
                    steps: [
                        {
                            id: "done",
                            kind: "action",
                            title: "Done",
                            body: "End",
                            next: null,
                        },
                    ],
                },
            ],
        });
        const out = renderMarkdown(flow, TARGETS.claude);
        // "step 1" alone would be ambiguous: numbering restarts per phase.
        expect(out).toContain("> A) **Wrap up** → step 1 of the Finish phase");
    });
    it("collapses the largest byMode group to 'otherwise'", () => {
        const flow = makeFlow({
            entries: { all: "main/pick", quick: "main/pick", deep: "main/pick" },
            phases: [
                {
                    id: "main",
                    title: "Main",
                    stepStyle: "headers",
                    steps: [
                        {
                            id: "pick",
                            kind: "branch",
                            title: "Pick",
                            body: "{{branches}}",
                            branches: [
                                {
                                    option: { letter: "A", label: "Continue" },
                                    next: {
                                        byMode: { all: "main/work", quick: null, deep: null },
                                    },
                                },
                                { option: { letter: "B", label: "Bail" }, next: null },
                            ],
                        },
                        {
                            id: "work",
                            kind: "action",
                            title: "Work",
                            body: "Work body",
                            next: null,
                        },
                    ],
                },
            ],
        });
        const out = renderMarkdown(flow, TARGETS.claude);
        expect(out).toContain("> A) **Continue** → step 2 (mode `all`); otherwise stop");
    });
});
